using BenchmarkDotNet.Running;
using BenchmarkDotNet.Toolchains.CsProj;
using TextAnalysis;

var config = DefaultConfig.Instance
    .AddJob(Job.ShortRun.WithToolchain(CsProjCoreToolchain.NetCoreApp90).WithId("net9.0"))
    .AddJob(Job.ShortRun.WithToolchain(CsProjCoreToolchain.NetCoreApp10_0).WithId("net10.0"));

BenchmarkRunner.Run<TextAnalyzerBenchmarks>(config);

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        // Generate a representative text corpus
        var words = new[] { "the", "quick", "brown", "fox", "jumps", "over", "the", "lazy", "dog",
            "performance", "benchmarking", "is", "important", "for", "software", "engineering",
            "dotnet", "runtime", "improvements", "can", "significantly", "impact", "throughput" };
        var rng = new Random(42);
        var parts = new string[5000];
        for (int i = 0; i < parts.Length; i++)
            parts[i] = words[rng.Next(words.Length)];
        string text = string.Join(' ', parts);
        _analyzer = new TextAnalyzer(text);
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}
EOF

